import type { HTMLAttributes, ReactNode } from "react";
import { cn } from "@/lib/utils";

type OdsMetricTone = "muted" | "positive" | "negative";

const subToneClass: Record<OdsMetricTone, string> = {
  muted: "text-[var(--fg-secondary)]",
  positive: "text-[var(--fg-positive)]",
  negative: "text-[var(--fg-negative)]",
};

interface OdsMetricCardProps extends HTMLAttributes<HTMLDivElement> {
  label: ReactNode;
  loading?: boolean;
  sub?: ReactNode;
  subTone?: OdsMetricTone;
  value: ReactNode;
}

function OdsMetricSkeleton({ className = "" }: { className?: string }) {
  return (
    <div
      className={cn("animate-pulse rounded-lg bg-[var(--bg-hover)]", className)}
    />
  );
}

export function OdsMetricCard({
  className,
  label,
  loading = false,
  sub,
  subTone = "muted",
  value,
  ...props
}: OdsMetricCardProps) {
  return (
    <div
      className={cn(
        "rounded-2xl border border-[var(--border-subtle)] bg-[var(--bg-surface-primary)] p-5",
        className
      )}
      {...props}
    >
      <div className="text-[14px] font-medium leading-[120%] text-[var(--fg-secondary)]">
        {label}
      </div>
      {loading ? (
        <>
          <OdsMetricSkeleton className="mt-3 h-7 w-28" />
          {sub ? <OdsMetricSkeleton className="mt-2 h-3 w-20" /> : null}
        </>
      ) : (
        <>
          <div className="mt-2 font-mono text-2xl font-semibold text-[var(--fg-base)]">
            {value}
          </div>
          {sub ? (
            <div className={cn("mt-1 text-xs", subToneClass[subTone])}>
              {sub}
            </div>
          ) : null}
        </>
      )}
    </div>
  );
}
